  1→/**
  2→ * Theme colors for TUI — mirrors src/lib/theme.ts (web app).
  3→ * Ink supports hex colors in modern terminals.
  4→ */
  5→
  6→export const colors = {
  7→  // Text hierarchy
  8→  textPrimary: "#d0d0d0",
  9→  textSecondary: "#8a8a8a",
 10→  textDim: "#767676",
 11→  textMuted: "#585858",
 12→
 13→  // Accents
 14→  accent: "#5fafff",
 15→  error: "#ff0000",
 16→
 17→  // Borders
 18→  border: "#5f5f87",
 19→
 20→  // Model family
 21→  modelOpus: "#ff5f87",
 22→  modelSonnet: "#5fafff",
 23→  modelHaiku: "#87d787",
 24→
 25→  // Token highlight
 26→  tokenHigh: "#ff8700",
 27→
 28→  // Ongoing indicator
 29→  ongoing: "#5faf00",
 30→
 31→  // Context usage
 32→  contextOk: "#87d787",
 33→  contextWarn: "#ff8700",
 34→  contextCrit: "#ff0000",
 35→
 36→  // Permission mode pills
 37→  pillBypass: "#ff0000",
 38→  pillAcceptEdits: "#af5fff",
 39→  pillPlan: "#87d787",
 40→
 41→  // Git branch
 42→  gitBranch: "#af5fff",
 43→
 44→  // Roles
 45→  roleUser: "#5fafff",
 46→  roleClaude: "#8a8a8a",
 47→  roleSystem: "#585858",
 48→
 49→  // Item types
 50→  itemThinking: "#767676",
 51→  itemOutput: "#d0d0d0",
 52→  itemTool: "#5fafff",
 53→  itemToolError: "#ff0000",
 54→  itemAgent: "#5fafaf",
 55→  itemTeammate: "#5fafff",
 56→  itemHook: "#ffdf00",
 57→} as const;
 58→
 59→export const teamColors: Record<string, string> = {
 60→  blue: "#5fafff",
 61→  green: "#87d787",
 62→  red: "#ff5f87",
 63→  yellow: "#ffdf00",
 64→  purple: "#d787ff",
 65→  cyan: "#5fafaf",
 66→  orange: "#ff8700",
 67→  pink: "#ff87af",
 68→};
 69→
 70→export function getModelColor(model: string): string {
 71→  if (model.includes("opus")) return colors.modelOpus;
 72→  if (model.includes("sonnet")) return colors.modelSonnet;
 73→  if (model.includes("haiku")) return colors.modelHaiku;
 74→  return colors.textSecondary;
 75→}
 76→
 77→export function getTeamColor(name: string): string {
 78→  return teamColors[name.toLowerCase()] ?? colors.accent;
 79→}
 80→
 81→export function getContextColor(pct: number): string {
 82→  if (pct < 50) return colors.contextOk;
 83→  if (pct < 80) return colors.contextWarn;
 84→  return colors.contextCrit;
 85→}
 86→
 87→export function getRoleBorderColor(role: string, isError: boolean): string {
 88→  if (isError) return colors.error;
 89→  switch (role) {
 90→    case "user":
 91→      return colors.roleUser;
 92→    case "claude":
 93→      return colors.roleClaude;
 94→    case "system":
 95→      return colors.roleSystem;
 96→    default:
 97→      return colors.border;
 98→  }
 99→}
100→
101→export function getItemColor(itemType: string, hasError: boolean): string {
102→  switch (itemType) {
103→    case "Thinking":
104→      return colors.itemThinking;
105→    case "Output":
106→      return colors.itemOutput;
107→    case "ToolCall":
108→      return hasError ? colors.itemToolError : colors.itemTool;
109→    case "Subagent":
110→      return colors.itemAgent;
111→    case "TeammateMessage":
112→      return colors.itemTeammate;
113→    case "HookEvent":
114→      return colors.itemHook;
115→    default:
116→      return colors.textDim;
117→  }
118→}
