  1→import type { ReactNode } from "react";
  2→import { Box, Text } from "ink";
  3→import type { DisplayMessage, DisplayItem } from "../api.js";
  4→import { formatDuration, truncate, roleColor, roleIcon, formatJson } from "../lib/format.js";
  5→import { colors, getItemColor, getTeamColor } from "../lib/theme.js";
  6→import { getItemIcon, getItemName, getItemSummary } from "../lib/items.js";
  7→import { StatsBar, statsFromMessage } from "./StatsBar.js";
  8→import { BrailleSpinner, OngoingDot } from "./OngoingDots.js";
  9→import { stableWindow } from "../lib/window.js";
 10→
 11→/** Limit text to maxLines while preserving newlines. Appends "…" if truncated. */
 12→function limitLines(text: string, maxLines: number): string {
 13→  const lines = text.split("\n");
 14→  if (lines.length <= maxLines) return text;
 15→  return lines.slice(0, maxLines).join("\n") + "\n…(" + (lines.length - maxLines) + " more lines)";
 16→}
 17→
 18→/** Clamp each line to maxWidth so bordered boxes don't overflow the terminal. */
 19→function clampLines(text: string, maxWidth: number): string {
 20→  return text
 21→    .split("\n")
 22→    .map((line) => (line.length > maxWidth ? line.slice(0, maxWidth - 1) + "…" : line))
 23→    .join("\n");
 24→}
 25→
 26→interface DetailViewProps {
 27→  message: DisplayMessage;
 28→  selectedItem: number;
 29→  expandedItems: Set<number>;
 30→  ongoing: boolean;
 31→  depth?: number;
 32→}
 33→
 34→function itemBorderColor(item: DisplayItem, isSelected: boolean): string {
 35→  if (isSelected) return colors.accent;
 36→  // Subagent items with messages get their team color
 37→  if (item.subagent_messages.length > 0 && item.team_color) {
 38→    return getTeamColor(item.team_color);
 39→  }
 40→  return getItemColor(item.item_type, !!item.tool_error);
 41→}
 42→
 43→export function DetailView({
 44→  message,
 45→  selectedItem,
 46→  expandedItems,
 47→  ongoing,
 48→  depth = 0,
 49→}: DetailViewProps) {
 50→  const cols = process.stdout.columns || 80;
 51→  const stats = statsFromMessage(message);
 52→  const items = message.items;
 53→
 54→  const windowSize = (process.stdout.rows || 24) - 8;
 55→  const { start, end } = stableWindow("detail", selectedItem, items.length, windowSize);
 56→  const visible = items.slice(start, end);
 57→
 58→  // Fixed-width name column — computed from ALL items so it doesn't shift
 59→  const maxNameLen = Math.max(4, ...items.map((it) => getItemName(it).length));
 60→
 61→  return (
 62→    <Box flexDirection="column">
 63→      {/* Message header */}
 64→      <Box
 65→        flexDirection="column"
 66→        borderStyle="single"
 67→        borderColor={colors.border}
 68→        borderLeft={false}
 69→        borderRight={false}
 70→        borderTop={false}
 71→        paddingX={1}
 72→      >
 73→        <Box gap={1}>
 74→          {depth > 0 ? <Text dimColor>{"▸".repeat(depth)} </Text> : null}
 75→          <Text bold color={roleColor(message.role)}>
 76→            {roleIcon(message.role)}{" "}
 77→            {message.role === "claude" ? "Claude" : message.role === "user" ? "User" : "System"}
 78→          </Text>
 79→          {message.subagent_label ? (
 80→            <Text color={colors.itemAgent}>[{message.subagent_label}]</Text>
 81→          ) : null}
 82→          <StatsBar stats={stats} />
 83→          {ongoing ? <BrailleSpinner /> : null}
 84→        </Box>
 85→        {items.length > 0 ? (
 86→          <Text dimColor wrap="truncate">
 87→            {truncate(message.content, cols - 4)}
 88→          </Text>
 89→        ) : null}
 90→      </Box>
 91→
 92→      {/* Full content when no items */}
 93→      {items.length === 0 ? (
 94→        <Box paddingX={1} flexDirection="column">
 95→          <Text wrap="wrap">{message.content}</Text>
 96→        </Box>
 97→      ) : (
 98→        <Box flexDirection="column" paddingTop={1}>
 99→          {visible.map((item, i) => {
100→            const idx = start + i;
101→            const isSelected = idx === selectedItem;
102→            const isExpanded = expandedItems.has(idx);
103→            const clr = itemBorderColor(item, isSelected);
104→            const hasAgent = item.subagent_messages.length > 0;
105→            const teamClr = item.team_color ? getTeamColor(item.team_color) : undefined;
106→
107→            return (
108→              <Box
109→                key={`${item.item_type}-${idx}-${item.tool_name || item.agent_id || ""}`}
110→                flexDirection="row"
111→                marginBottom={0}
112→              >
113→                {/* Left accent — double bar for subagents with messages */}
114→                <Text color={hasAgent && teamClr ? teamClr : clr}>{hasAgent ? "┃" : "│"}</Text>
115→                <Box flexDirection="column" flexGrow={1} paddingLeft={1}>
116→                  {/* Item header */}
117→                  <Box gap={1}>
118→                    <Text
119→                      bold={isSelected}
120→                      inverse={isSelected}
121→                      color={hasAgent && teamClr ? teamClr : clr}
122→                    >
123→                      {isExpanded ? "▼" : "▶"} {getItemIcon(item)}{" "}
124→                      {getItemName(item).padEnd(maxNameLen)}
125→                    </Text>
126→                    {getItemSummary(item) ? (
127→                      <Text dimColor>
128→                        — {truncate(getItemSummary(item), cols - maxNameLen - 12)}
129→                      </Text>
130→                    ) : null}
131→                    {item.duration_ms > 0 ? (
132→                      <Text dimColor>{formatDuration(item.duration_ms)}</Text>
133→                    ) : null}
134→                    {item.subagent_ongoing ? <OngoingDot /> : null}
135→                    {hasAgent ? (
136→                      <Text color={teamClr || colors.itemAgent} dimColor>
137→                        [{item.subagent_messages.length} msg]
138→                      </Text>
139→                    ) : null}
140→                    {item.agent_id ? <Text dimColor>[{item.agent_id.slice(0, 8)}]</Text> : null}
141→                  </Box>
142→
143→                  {/* Expanded body */}
144→                  {isExpanded && <DetailItemBody item={item} cols={cols} />}
145→                </Box>
146→              </Box>
147→            );
148→          })}
149→        </Box>
150→      )}
151→    </Box>
152→  );
153→}
154→
155→/** Bordered container with a label in the top-left corner. */
156→function Section({
157→  label,
158→  width,
159→  children,
160→}: {
161→  label: string;
162→  width: number;
163→  children: ReactNode;
164→}) {
165→  return (
166→    <Box flexDirection="column" borderStyle="round" borderColor={colors.border} width={width}>
167→      <Box paddingX={1} flexDirection="column">
168→        <Text bold color={colors.textMuted}>
169→          {label}
170→        </Text>
171→        <Box marginTop={1} flexDirection="column">
172→          {children}
173→        </Box>
174→      </Box>
175→    </Box>
176→  );
177→}
178→
179→/** Plain bordered container (no label). */
180→function Container({ width, children }: { width: number; children: ReactNode }) {
181→  return (
182→    <Box flexDirection="column" borderStyle="round" borderColor={colors.border} width={width}>
183→      <Box paddingX={1} flexDirection="column">
184→        {children}
185→      </Box>
186→    </Box>
187→  );
188→}
189→
190→const MAX_BODY_LINES = 40;
191→// border (2) + paddingX (2) + left-accent bar + padding (2) = ~6
192→const BOX_OVERHEAD = 6;
193→
194→function DetailItemBody({ item, cols }: { item: DisplayItem; cols: number }) {
195→  // Width available inside the box for text content
196→  const innerWidth = cols - BOX_OVERHEAD - 4; // 4 = border(2) + paddingX(2) inside the box
197→  const boxWidth = cols - BOX_OVERHEAD;
198→  const clamp = (text: string) => clampLines(limitLines(text, MAX_BODY_LINES), innerWidth);
199→
200→  switch (item.item_type) {
201→    case "Thinking":
202→      return (
203→        <Container width={boxWidth}>
204→          <Text color={colors.itemThinking} wrap="truncate">
205→            {clamp(item.text || "Thinking content is not recorded in session logs.")}
206→          </Text>
207→        </Container>
208→      );
209→    case "Output":
210→      return (
211→        <Container width={boxWidth}>
212→          <Text wrap="truncate">{clamp(item.text)}</Text>
213→        </Container>
214→      );
215→    case "ToolCall":
216→      return (
217→        <Box flexDirection="column">
218→          {item.tool_input && (
219→            <Section label="INPUT" width={boxWidth}>
220→              <Text dimColor wrap="truncate">
221→                {clamp(formatJson(item.tool_input))}
222→              </Text>
223→            </Section>
224→          )}
225→          {item.tool_result && (
226→            <Section label="RESULT" width={boxWidth}>
227→              <Text color={item.tool_error ? colors.error : undefined} wrap="truncate">
228→                {clamp(item.tool_result)}
229→              </Text>
230→            </Section>
231→          )}
232→        </Box>
233→      );
234→    case "Subagent":
235→      return (
236→        <Box flexDirection="column">
237→          {(item.agent_id || item.subagent_desc) && (
238→            <Container width={boxWidth}>
239→              {item.agent_id && (
240→                <Box gap={1}>
241→                  <Text color={colors.textMuted} bold>
242→                    ID
243→                  </Text>
244→                  <Text dimColor>{item.agent_id}</Text>
245→                </Box>
246→              )}
247→              {item.subagent_desc && (
248→                <Box gap={1}>
249→                  <Text color={colors.textMuted} bold>
250→                    DESC
251→                  </Text>
252→                  <Text wrap="truncate">{item.subagent_desc}</Text>
253→                </Box>
254→              )}
255→            </Container>
256→          )}
257→          {item.subagent_prompt && (
258→            <Section label="PROMPT" width={boxWidth}>
259→              <Text wrap="truncate">{clamp(item.subagent_prompt)}</Text>
260→            </Section>
261→          )}
262→          {item.text && (
263→            <Section label="CONTENT" width={boxWidth}>
264→              <Text wrap="truncate">{clamp(item.text)}</Text>
265→            </Section>
266→          )}
267→        </Box>
268→      );
269→    case "TeammateMessage":
270→      return (
271→        <Container width={boxWidth}>
272→          <Text wrap="truncate">{clamp(item.text)}</Text>
273→        </Container>
274→      );
275→    case "HookEvent":
276→      return (
277→        <Container width={boxWidth}>
278→          <Box gap={1}>
279→            <Text color={colors.textMuted} bold>
280→              HOOK
281→            </Text>
282→            <Text>
283→              {item.hook_event}: {item.hook_name}
284→            </Text>
285→          </Box>
286→          {item.hook_command && (
287→            <Box gap={1}>
288→              <Text color={colors.textMuted} bold>
289→                CMD
290→              </Text>
291→              <Text dimColor>{item.hook_command}</Text>
292→            </Box>
293→          )}
294→        </Container>
295→      );
296→    default:
297→      return (
298→        <Container width={boxWidth}>
299→          <Text wrap="truncate">{clamp(item.text)}</Text>
300→        </Container>
301→      );
302→  }
303→}
