  1→import { useMemo } from "react";
  2→import { Box, Text } from "ink";
  3→import { Spinner } from "@inkjs/ui";
  4→import type { SessionInfo } from "../api.js";
  5→import {
  6→  formatTokens,
  7→  formatCost,
  8→  timeAgo,
  9→  truncate,
 10→  shortModel,
 11→  modelColor,
 12→} from "../lib/format.js";
 13→import { OngoingDot } from "./OngoingDots.js";
 14→import { colors } from "../lib/theme.js";
 15→import { stableWindow } from "../lib/window.js";
 16→
 17→interface SessionPickerProps {
 18→  sessions: SessionInfo[];
 19→  loading: boolean;
 20→  error: string;
 21→  selectedIndex: number;
 22→}
 23→
 24→interface DateGroup {
 25→  category: string;
 26→  items: SessionInfo[];
 27→}
 28→
 29→function groupByDate(items: SessionInfo[]): DateGroup[] {
 30→  const now = new Date();
 31→  const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate());
 32→  const yesterdayStart = new Date(todayStart.getTime() - 86400000);
 33→  const weekStart = new Date(todayStart.getTime() - 7 * 86400000);
 34→  const monthStart = new Date(todayStart.getTime() - 30 * 86400000);
 35→
 36→  const groups: Record<string, SessionInfo[]> = {};
 37→  const order = ["Today", "Yesterday", "This Week", "This Month", "Older"];
 38→
 39→  for (const item of items) {
 40→    const d = new Date(item.mod_time);
 41→    let cat: string;
 42→    if (d >= todayStart) cat = "Today";
 43→    else if (d >= yesterdayStart) cat = "Yesterday";
 44→    else if (d >= weekStart) cat = "This Week";
 45→    else if (d >= monthStart) cat = "This Month";
 46→    else cat = "Older";
 47→    (groups[cat] ??= []).push(item);
 48→  }
 49→
 50→  for (const cat of order) {
 51→    if (groups[cat]) {
 52→      groups[cat].sort((a, b) => new Date(b.mod_time).getTime() - new Date(a.mod_time).getTime());
 53→    }
 54→  }
 55→
 56→  return order
 57→    .filter((cat) => groups[cat]?.length)
 58→    .map((category) => ({ category, items: groups[category] }));
 59→}
 60→
 61→export function SessionPicker({ sessions, loading, error, selectedIndex }: SessionPickerProps) {
 62→  const dateGroups = useMemo(() => groupByDate(sessions), [sessions]);
 63→
 64→  const totalTokens = useMemo(
 65→    () => sessions.reduce((sum, s) => sum + s.total_tokens, 0),
 66→    [sessions],
 67→  );
 68→  const totalCost = useMemo(() => sessions.reduce((sum, s) => sum + s.cost_usd, 0), [sessions]);
 69→
 70→  if (loading) {
 71→    return (
 72→      <Box padding={1}>
 73→        <Spinner label="Discovering sessions..." />
 74→      </Box>
 75→    );
 76→  }
 77→
 78→  if (error) {
 79→    return (
 80→      <Box padding={1}>
 81→        <Text color={colors.error}>{error}</Text>
 82→      </Box>
 83→    );
 84→  }
 85→
 86→  // 2 lines per session card + date headers
 87→  const rows = process.stdout.rows || 24;
 88→  const windowSize = Math.max(3, Math.floor((rows - 4) / 2));
 89→  const { start, end } = stableWindow("picker", selectedIndex, sessions.length, windowSize);
 90→
 91→  let flatIdx = 0;
 92→  const cols = process.stdout.columns || 80;
 93→
 94→  return (
 95→    <Box flexDirection="column">
 96→      {/* Header bar */}
 97→      <Box
 98→        paddingX={1}
 99→        gap={2}
100→        borderStyle="single"
101→        borderLeft={false}
102→        borderRight={false}
103→        borderTop={false}
104→        borderColor={colors.border}
105→      >
106→        <Text bold>Sessions ({sessions.length})</Text>
107→        {totalTokens > 0 && <Text dimColor>{formatTokens(totalTokens)} tok</Text>}
108→        {totalCost > 0 && <Text color={colors.tokenHigh}>{formatCost(totalCost)}</Text>}
109→      </Box>
110→
111→      {/* Session cards grouped by date */}
112→      {dateGroups.map((group) => {
113→        const groupItems = group.items.map((s) => {
114→          const idx = flatIdx++;
115→          return { session: s, idx };
116→        });
117→
118→        const firstInGroup = groupItems[0]?.idx ?? 0;
119→        const lastInGroup = groupItems[groupItems.length - 1]?.idx ?? 0;
120→        if (lastInGroup < start || firstInGroup >= end) return null;
121→
122→        return (
123→          <Box key={group.category} flexDirection="column">
124→            {firstInGroup >= start && firstInGroup < end && (
125→              <Box paddingX={1} marginTop={1}>
126→                <Text dimColor bold>
127→                  {group.category}
128→                </Text>
129→              </Box>
130→            )}
131→            {groupItems.map(({ session: s, idx }) => {
132→              if (idx < start || idx >= end) return null;
133→              const isSelected = idx === selectedIndex;
134→              const model = s.model ? shortModel(s.model) : "";
135→              const borderClr = isSelected
136→                ? colors.accent
137→                : s.is_ongoing
138→                  ? colors.ongoing
139→                  : colors.border;
140→              const msgMaxLen = cols - 6;
141→
142→              return (
143→                <Box key={s.path} flexDirection="column">
144→                  {/* Line 1: message */}
145→                  <Box>
146→                    <Text color={borderClr}>{isSelected ? " ▸ " : " │ "}</Text>
147→                    <Text bold={isSelected} color={isSelected ? colors.accent : colors.textPrimary}>
148→                      {truncate(s.first_message || s.session_id, msgMaxLen)}
149→                    </Text>
150→                    {s.is_ongoing && <OngoingDot />}
151→                  </Box>
152→                  {/* Line 2: metadata */}
153→                  <Box>
154→                    <Text color={borderClr}>{isSelected ? " ▸ " : " │ "}</Text>
155→                    {model && <Text color={modelColor(s.model)}>{model}</Text>}
156→                    <Text dimColor> {s.turn_count}t</Text>
157→                    {s.total_tokens > 0 && <Text dimColor> {formatTokens(s.total_tokens)}</Text>}
158→                    {s.cost_usd > 0 && (
159→                      <Text color={colors.tokenHigh}> {formatCost(s.cost_usd)}</Text>
160→                    )}
161→                    <Text dimColor> {timeAgo(s.mod_time)}</Text>
162→                  </Box>
163→                </Box>
164→              );
165→            })}
166→          </Box>
167→        );
168→      })}
169→
170→      {sessions.length === 0 && !loading && (
171→        <Box paddingX={1}>
172→          <Text dimColor>No sessions found</Text>
173→        </Box>
174→      )}
175→    </Box>
176→  );
177→}
