  1→import { Box, Text } from "ink";
  2→import type { DisplayMessage } from "../api.js";
  3→import { truncate, roleColor, roleIcon, shortModel, modelColor, firstLine } from "../lib/format.js";
  4→import { colors, getRoleBorderColor, getItemColor, getTeamColor } from "../lib/theme.js";
  5→import { StatsBar, statsFromMessage } from "./StatsBar.js";
  6→import { BrailleSpinner } from "./OngoingDots.js";
  7→import { stableWindow } from "../lib/window.js";
  8→
  9→interface MessageListProps {
 10→  messages: DisplayMessage[];
 11→  selectedIndex: number;
 12→  expandedSet: Set<number>;
 13→  ongoing: boolean;
 14→}
 15→
 16→export function MessageList({ messages, selectedIndex, expandedSet, ongoing }: MessageListProps) {
 17→  const cols = process.stdout.columns || 80;
 18→  const contentWidth = Math.max(cols - 30, 40);
 19→  // Each message renders 3 lines (header + content + stats)
 20→  const rows = process.stdout.rows || 24;
 21→  const windowSize = Math.max(4, Math.floor((rows - 4) / 3));
 22→  const { start, end } = stableWindow("messages", selectedIndex, messages.length, windowSize);
 23→  const visible = messages.slice(start, end);
 24→
 25→  if (messages.length === 0) {
 26→    return (
 27→      <Box paddingX={1}>
 28→        <Text dimColor>No messages loaded</Text>
 29→      </Box>
 30→    );
 31→  }
 32→
 33→  return (
 34→    <Box flexDirection="column">
 35→      {visible.map((msg, i) => {
 36→        const idx = start + i;
 37→        const isSelected = idx === selectedIndex;
 38→        const isExpanded = expandedSet.has(idx);
 39→        const isLast = idx === messages.length - 1;
 40→        const stats = statsFromMessage(msg);
 41→        const model = msg.model ? shortModel(msg.model) : "";
 42→
 43→        if (msg.role === "compact") {
 44→          return (
 45→            <Box key={`compact-${idx}`} paddingX={1} justifyContent="center">
 46→              <Text dimColor>────── {msg.content} ──────</Text>
 47→            </Box>
 48→          );
 49→        }
 50→
 51→        const contentPreview = isExpanded
 52→          ? msg.content
 53→          : truncate(firstLine(msg.content), contentWidth);
 54→        const borderClr = isSelected ? colors.accent : getRoleBorderColor(msg.role, msg.is_error);
 55→
 56→        return (
 57→          <Box key={`msg-${idx}-${msg.role}`} flexDirection="row" marginBottom={0}>
 58→            <Text color={borderClr}>│</Text>
 59→            <Box flexDirection="column" flexGrow={1} paddingLeft={1}>
 60→              <Box gap={1}>
 61→                <Text
 62→                  bold
 63→                  inverse={isSelected}
 64→                  color={isSelected ? colors.accent : roleColor(msg.role)}
 65→                >
 66→                  {isSelected ? "▸ " : "  "}
 67→                  {roleIcon(msg.role)}{" "}
 68→                  {msg.role === "claude" ? "Claude" : msg.role === "user" ? "User" : "System"}
 69→                </Text>
 70→                {model ? (
 71→                  <Text color={modelColor(msg.model)} dimColor={!isSelected}>
 72→                    {model}
 73→                  </Text>
 74→                ) : null}
 75→                {msg.subagent_label ? (
 76→                  <Text color={colors.itemAgent} dimColor>
 77→                    [{msg.subagent_label}]
 78→                  </Text>
 79→                ) : null}
 80→                {isLast && ongoing ? <BrailleSpinner /> : null}
 81→                {isSelected ? (
 82→                  <Text dimColor>
 83→                    [{idx + 1}/{messages.length}]
 84→                  </Text>
 85→                ) : null}
 86→              </Box>
 87→
 88→              <Box>
 89→                <Text dimColor={!isSelected} wrap={isExpanded ? "wrap" : "truncate"}>
 90→                  {contentPreview}
 91→                </Text>
 92→              </Box>
 93→
 94→              <StatsBar stats={stats} />
 95→
 96→              {isExpanded && msg.items.length > 0 && (
 97→                <Box flexDirection="column" paddingLeft={2} marginTop={0}>
 98→                  {msg.items.map((item) => (
 99→                    <Box
100→                      key={`${idx}-${item.item_type}-${item.tool_name || item.agent_id || ""}-${item.duration_ms}`}
101→                      flexDirection="row"
102→                    >
103→                      <Text color={item.team_color ? getTeamColor(item.team_color) : colors.border}>
104→                        {item.subagent_messages.length > 0 ? "┃" : "│"}
105→                      </Text>
106→                      <Box paddingLeft={1}>
107→                        {item.item_type === "ToolCall" ? (
108→                          <Text color={getItemColor("ToolCall", !!item.tool_error)}>
109→                            ⚙ {item.tool_name}
110→                            {item.tool_summary
111→                              ? ` — ${truncate(item.tool_summary, contentWidth - 20)}`
112→                              : ""}
113→                          </Text>
114→                        ) : item.item_type === "Thinking" ? (
115→                          <Text color={colors.itemThinking}>
116→                            ◆ {truncate(item.text, contentWidth - 10)}
117→                          </Text>
118→                        ) : item.item_type === "Output" ? (
119→                          <Text color={colors.itemOutput}>
120→                            ▪ {truncate(item.text, contentWidth - 10)}
121→                          </Text>
122→                        ) : item.item_type === "Subagent" ? (
123→                          <Text
124→                            color={
125→                              item.team_color ? getTeamColor(item.team_color) : colors.itemAgent
126→                            }
127→                          >
128→                            ✦ {item.subagent_type || "Agent"}
129→                            {item.subagent_desc
130→                              ? ` — ${truncate(item.subagent_desc, contentWidth - 20)}`
131→                              : ""}
132→                            {item.subagent_ongoing ? " ●" : ""}
133→                            {item.subagent_messages.length > 0
134→                              ? ` [${item.subagent_messages.length} msg]`
135→                              : ""}
136→                          </Text>
137→                        ) : item.item_type === "TeammateMessage" ? (
138→                          <Text
139→                            color={
140→                              item.team_color ? getTeamColor(item.team_color) : colors.itemTeammate
141→                            }
142→                          >
143→                            ◈ {item.team_member_name || "Teammate"}:{" "}
144→                            {truncate(item.text, contentWidth - 20)}
145→                          </Text>
146→                        ) : item.item_type === "HookEvent" ? (
147→                          <Text color={colors.itemHook}>
148→                            ⚡ {item.hook_event}: {item.hook_name}
149→                          </Text>
150→                        ) : (
151→                          <Text color={colors.textDim}>
152→                            {item.item_type}: {truncate(item.text, contentWidth - 20)}
153→                          </Text>
154→                        )}
155→                      </Box>
156→                    </Box>
157→                  ))}
158→                </Box>
159→              )}
160→            </Box>
161→          </Box>
162→        );
163→      })}
164→    </Box>
165→  );
166→}
