 13→)
 14→
 15→// pickerSessionsMsg delivers discovered sessions to the model.
 16→type pickerSessionsMsg struct {
 17→	sessions []parser.SessionInfo
 18→	err      error
 19→}
 20→
 21→// loadSessionMsg delivers a parsed session ready for the list view,
 22→// including classified messages and offset for watcher handoff.
 23→type loadSessionMsg struct {
 24→	loadResult
 25→	err error
 26→}
 27→
 28→// pickerTickMsg drives the ongoing spinner animation (100ms interval).
 29→type pickerTickMsg time.Time
 30→
 31→func pickerTickCmd() tea.Cmd {
 32→	return tea.Tick(100*time.Millisecond, func(t time.Time) tea.Msg {
 33→		return pickerTickMsg(t)
 34→	})
 35→}
 36→
 37→// loadPickerSessionsCmd discovers sessions across the given project directories
 38→// (main repo + worktree dirs). When cache is non-nil, unchanged files return
 39→// cached metadata.
 40→func loadPickerSessionsCmd(projectDirs []string, cache *parser.SessionCache) tea.Cmd {
 41→	return func() tea.Msg {
 42→		var sessions []parser.SessionInfo
 43→		var err error
 44→		if cache != nil {
 45→			sessions, err = cache.DiscoverAllProjectSessions(projectDirs)
 46→		} else {
 47→			sessions, err = parser.DiscoverAllProjectSessions(projectDirs)
 48→		}
 49→		return pickerSessionsMsg{sessions: sessions, err: err}
 50→	}
 51→}
 52→
 53→// loadSessionCmd returns a command that loads a session file into messages.
 54→// Delegates to loadSession so the parsing pipeline lives in one place.
 55→func loadSessionCmd(path string) tea.Cmd {
 56→	return func() tea.Msg {
 57→		result, err := loadSession(path)
 58→		if err != nil {
 59→			return loadSessionMsg{err: err}
 60→		}
 61→		return loadSessionMsg{loadResult: result}
 62→	}
 63→}
