  5→import { colors, getContextColor } from "../lib/theme.js";
  6→import { BrailleSpinner } from "./OngoingDots.js";
  7→
  8→interface InfoBarProps {
  9→  meta: SessionMeta;
 10→  messages: DisplayMessage[];
 11→  sessionTotals: SessionTotals;
 12→  sessionPath: string;
 13→  ongoing: boolean;
 14→}
 15→
 16→function shortPath(cwd: string): string {
 17→  if (!cwd) return "";
 18→  const parts = cwd.split("/").filter(Boolean);
 19→  return parts[parts.length - 1] ?? cwd;
 20→}
 21→
 22→function shortMode(mode: string): string {
 23→  switch (mode) {
 24→    case "acceptEdits":
 25→      return "auto-edit";
 26→    case "bypassPermissions":
 27→      return "yolo";
 28→    case "plan":
 29→      return "plan";
 30→    default:
 31→      return mode;
 32→  }
 33→}
 34→
 35→function contextPercent(msgs: DisplayMessage[]): number {
 36→  const contextWindowSize = 1_000_000;
 37→  for (let i = msgs.length - 1; i >= 0; i--) {
 38→    if (msgs[i].role === "claude" && msgs[i].context_tokens > 0) {
 39→      return Math.min(Math.floor((msgs[i].context_tokens * 100) / contextWindowSize), 100);
 40→    }
 41→  }
 42→  return -1;
 43→}
 44→
 45→function modeColor(mode: string): string {
 46→  switch (mode) {
 47→    case "bypassPermissions":
 48→      return colors.pillBypass;
 49→    case "acceptEdits":
 50→      return colors.pillAcceptEdits;
 51→    case "plan":
 52→      return colors.pillPlan;
 53→    default:
 54→      return colors.textPrimary;
 55→  }
 56→}
 57→
 58→export function InfoBar({ meta, messages, sessionTotals, sessionPath, ongoing }: InfoBarProps) {
 59→  const projectName = shortPath(meta.cwd);
 60→  const sessionId = sessionPath.split("/").pop()?.replace(".jsonl", "") || "";
 61→  const branch = meta.git_branch;
 62→  const mode = meta.permission_mode;
 63→  const ctxPct = useMemo(() => contextPercent(messages), [messages]);
 64→
 65→  return (
 66→    <Box
 67→      paddingX={1}
 68→      borderStyle="single"
 69→      borderLeft={false}
 70→      borderRight={false}
 71→      borderColor={colors.border}
 72→    >
 73→      {/* Left: project, session, branch, mode */}
 74→      <Box gap={1}>
 75→        {projectName ? (
 76→          <Text bold color={colors.accent}>
 77→            {projectName}
 78→          </Text>
 79→        ) : null}
 80→        {sessionId ? <Text color={colors.textDim}>{sessionId.slice(0, 8)}</Text> : null}
 81→        {branch ? <Text color={colors.gitBranch}>{branch}</Text> : null}
 82→        {mode && mode !== "default" ? (
 83→          <Text color={modeColor(mode)} bold>
 84→            [{shortMode(mode)}]
 85→          </Text>
 86→        ) : null}
 87→      </Box>
 88→
 89→      {/* Spacer */}
 90→      <Box flexGrow={1} />
 91→
 92→      {/* Right: ctx, tokens, cost, ongoing */}
 93→      <Box gap={1}>
 94→        {ctxPct >= 0 ? <Text color={getContextColor(ctxPct)}>ctx {ctxPct}%</Text> : null}
 95→        {sessionTotals.total_tokens > 0 ? (
 96→          <Text color={colors.textDim}>{formatTokens(sessionTotals.total_tokens)} tok</Text>
 97→        ) : null}
 98→        {sessionTotals.cost_usd > 0 ? (
 99→          <Text color={colors.tokenHigh}>{formatCost(sessionTotals.cost_usd)}</Text>
100→        ) : null}
101→        {ongoing ? <BrailleSpinner /> : null}
102→      </Box>
103→    </Box>
104→  );
105→}
