31→function hasAny(s: Stats): boolean {
32→  return (
33→    s.tokens > 0 ||
34→    s.toolCount > 0 ||
35→    s.thinkingCount > 0 ||
36→    s.outputCount > 0 ||
37→    s.durationMs > 0 ||
38→    s.agentCount > 0 ||
39→    s.spawnCount > 0
