27→export function DebugViewer({ entries, selectedIndex }: DebugViewerProps) {
28→  const cols = process.stdout.columns || 80;
29→  const rows = process.stdout.rows || 24;
30→  const windowSize = Math.max(4, rows - 6);
31→  const { start, end } = stableWindow("debug", selectedIndex, entries.length, windowSize);
32→  const visible = entries.slice(start, end);
