 1→/**
 2→ * Stable windowing for TUI lists — only scrolls when the selection
 3→ * reaches the edge of the visible window (2-item margin).
 4→ * Prevents "shaking" caused by center-following recalculation.
 5→ */
 6→
 7→const windowStarts = new Map<string, number>();
 8→
 9→export function stableWindow(
10→  id: string,
11→  selectedIndex: number,
12→  totalItems: number,
13→  windowSize: number,
14→): { start: number; end: number } {
15→  const maxStart = Math.max(0, totalItems - windowSize);
16→  let start = windowStarts.get(id) ?? 0;
17→
18→  // Clamp stored start to valid range
19→  start = Math.min(start, maxStart);
20→
21→  // Only scroll if selection goes outside the visible window (with 1-item margin)
22→  if (selectedIndex < start + 1) {
23→    start = Math.max(0, selectedIndex - 1);
24→  } else if (selectedIndex >= start + windowSize - 1) {
25→    start = Math.min(maxStart, selectedIndex - windowSize + 2);
26→  }
27→
28→  windowStarts.set(id, start);
29→  const end = Math.min(totalItems, start + windowSize);
30→  return { start, end };
31→}
