 74→      } catch (e) {
 75→        if (cancelled) return;
 76→        if (retries > 0) {
 77→          await new Promise((r) => setTimeout(r, 1000));
 78→          if (!cancelled) return attempt(retries - 1);
 79→        }
 80→        setPickerError(`Cannot connect to backend. Is the app running?\n${e}`);
 81→        setPickerLoading(false);
