import { useMemo } from "react";
import { Box, Text } from "ink";
import type { SessionInfo } from "../api.js";
import { colors } from "../lib/theme.js";
import { OngoingDot } from "./OngoingDots.js";
import { buildFlatItems } from "../../../shared/projectTree.js";
import type { FlatItem } from "../../../shared/projectTree.js";

interface ProjectTreeProps {
  sessions: SessionInfo[];
  selectedProject: string | null;
  highlightedIndex: number;
  isFocused: boolean;
}

export type { FlatItem };

export function useProjectEntries(sessions: SessionInfo[]): FlatItem[] {
  return useMemo(() => buildFlatItems(sessions), [sessions]);
}

export function ProjectTree({
  sessions,
  selectedProject,
  highlightedIndex,
  isFocused,
}: ProjectTreeProps) {
  const entries = useProjectEntries(sessions);
  // Dynamic width: min 24, adapts to longest entry
  // Allow up to 40% of terminal width for sidebar, min 28
  const termCols = process.stdout.columns || 80;
  const maxWidth = Math.floor(termCols * 0.4);
  const contentWidth = Math.max(
    28,
    ...entries.map((e) => e.name.length + e.depth * 2 + String(e.count).length + 8),
  );
  const sidebarWidth = Math.min(maxWidth, contentWidth);

  return (
    <Box
      flexDirection="column"
      borderStyle="single"
      borderColor={isFocused ? colors.accent : colors.border}
      width={sidebarWidth}
    >
      {/* Header */}
      <Box paddingX={1}>
        <Text bold dimColor>
          Projects
        </Text>
      </Box>

      {/* Tree items */}
      {entries.map((item, idx) => {
        const isSelected =
          !item.isGroup &&
          (item.key === selectedProject || (item.key === null && selectedProject === null));
        const isHighlighted = isFocused && idx === highlightedIndex;
        const indent = "  ".repeat(item.depth);
        const branch = item.depth > 0 ? "└ " : "";
        const icon = isSelected && !item.isGroup ? "▸" : " ";
        const label = item.isGroup ? `⑃ ${item.name}` : item.name;

        return (
          <Box key={item.key ?? "__all__"} flexDirection="column">
            {/* Blank line before root-level items for vertical breathing room */}
            {item.depth === 0 && idx > 0 ? (
              <Box>
                <Text> </Text>
              </Box>
            ) : null}
            <Box paddingX={1}>
              <Text
                inverse={isHighlighted}
                bold={isSelected}
                color={isSelected ? colors.accent : item.isGroup ? colors.textDim : undefined}
                dimColor={item.isGroup}
                wrap="truncate"
              >
                {icon}
                {indent}
                {branch}
                {label} <Text dimColor>{item.count}</Text>
                {item.ongoing ? " " : ""}
              </Text>
              {item.ongoing ? <OngoingDot /> : null}
            </Box>
          </Box>
        );
      })}
    </Box>
  );
}

import { useMemo } from "react";
import { Box, Text } from "ink";
import { Spinner } from "@inkjs/ui";
import type { SessionInfo } from "../api.js";
import {
  formatTokens,
  formatCost,
  timeAgo,
  truncate,
  shortModel,
  modelColor,
} from "../lib/format.js";
import { OngoingDot } from "./OngoingDots.js";
import { colors } from "../lib/theme.js";
import { stableWindow } from "../lib/window.js";

interface SessionPickerProps {
  sessions: SessionInfo[];
  loading: boolean;
  error: string;
  selectedIndex: number;
}

interface DateGroup {
  category: string;
  items: SessionInfo[];
}

function groupByDate(items: SessionInfo[]): DateGroup[] {
  const now = new Date();
  const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate());
  const yesterdayStart = new Date(todayStart.getTime() - 86400000);
  const weekStart = new Date(todayStart.getTime() - 7 * 86400000);
  const monthStart = new Date(todayStart.getTime() - 30 * 86400000);

  const groups: Record<string, SessionInfo[]> = {};
  const order = ["Today", "Yesterday", "This Week", "This Month", "Older"];

  for (const item of items) {
    const d = new Date(item.mod_time);
    let cat: string;
    if (d >= todayStart) cat = "Today";
    else if (d >= yesterdayStart) cat = "Yesterday";
    else if (d >= weekStart) cat = "This Week";
    else if (d >= monthStart) cat = "This Month";
    else cat = "Older";
    (groups[cat] ??= []).push(item);
  }

  for (const cat of order) {
    if (groups[cat]) {
      groups[cat].sort((a, b) => new Date(b.mod_time).getTime() - new Date(a.mod_time).getTime());
    }
  }

  return order
    .filter((cat) => groups[cat]?.length)
    .map((category) => ({ category, items: groups[category] }));
}

export function SessionPicker({ sessions, loading, error, selectedIndex }: SessionPickerProps) {
  const dateGroups = useMemo(() => groupByDate(sessions), [sessions]);

  const totalTokens = useMemo(
    () => sessions.reduce((sum, s) => sum + s.total_tokens, 0),
    [sessions],
  );
  const totalCost = useMemo(() => sessions.reduce((sum, s) => sum + s.cost_usd, 0), [sessions]);

  if (loading) {
    return (
      <Box padding={1}>
        <Spinner label="Discovering sessions..." />
      </Box>
    );
  }

  if (error) {
    return (
      <Box padding={1}>
        <Text color={colors.error}>{error}</Text>
      </Box>
    );
  }

  // 2 lines per session card + date headers
  const rows = process.stdout.rows || 24;
  const windowSize = Math.max(3, Math.floor((rows - 4) / 2));
  const { start, end } = stableWindow("picker", selectedIndex, sessions.length, windowSize);

  let flatIdx = 0;
  const cols = process.stdout.columns || 80;

  return (
    <Box flexDirection="column">
      {/* Header bar */}
      <Box
        paddingX={1}
        gap={2}
        borderStyle="single"
        borderLeft={false}
        borderRight={false}
        borderTop={false}
        borderColor={colors.border}
      >
        <Text bold>Sessions ({sessions.length})</Text>
        {totalTokens > 0 && <Text dimColor>{formatTokens(totalTokens)} tok</Text>}
        {totalCost > 0 && <Text color={colors.tokenHigh}>{formatCost(totalCost)}</Text>}
      </Box>

      {/* Session cards grouped by date */}
      {dateGroups.map((group) => {
        const groupItems = group.items.map((s) => {
          const idx = flatIdx++;
          return { session: s, idx };
        });

        const firstInGroup = groupItems[0]?.idx ?? 0;
        const lastInGroup = groupItems[groupItems.length - 1]?.idx ?? 0;
        if (lastInGroup < start || firstInGroup >= end) return null;

        return (
          <Box key={group.category} flexDirection="column">
            {firstInGroup >= start && firstInGroup < end && (
              <Box paddingX={1} marginTop={1}>
                <Text dimColor bold>
                  {group.category}
                </Text>
              </Box>
            )}
            {groupItems.map(({ session: s, idx }) => {
              if (idx < start || idx >= end) return null;
              const isSelected = idx === selectedIndex;
              const model = s.model ? shortModel(s.model) : "";
              const msgMaxLen = cols - 6;

              return (
                <Box key={s.path} flexDirection="column">
                  {/* Line 1: message preview */}
                  <Box>
                    <Text color={isSelected ? colors.accent : colors.border}>
                      {isSelected ? " \u25B8 " : " \u2502 "}
                    </Text>
                    {s.is_ongoing && (
                      <>
                        <OngoingDot />
                        <Text> </Text>
                      </>
                    )}
                    <Text
                      bold={isSelected}
                      color={isSelected ? colors.accent : colors.textPrimary}
                      backgroundColor={isSelected ? colors.pickerSelectedBg : undefined}
                    >
                      {truncate(s.first_message || s.session_id, msgMaxLen)}
                    </Text>
                  </Box>
                  {/* Line 2: metadata with Nerd Font icons — matches Go TUI */}
                  <Box>
                    <Text color={isSelected ? colors.accent : colors.border}>
                      {isSelected ? " \u25B8 " : " \u2502 "}
                    </Text>
                    {model && (
                      <Text color={modelColor(s.model)}>
                        {model.padEnd(10)}
                      </Text>
                    )}
                    {s.git_branch ? (
                      <Text color={colors.gitBranch}>
                        {" "}{"\uE0A0"} {truncate(s.git_branch, 20)}
                      </Text>
                    ) : null}
                    <Text dimColor>
                      {" "}{"\uF086"} {String(s.turn_count).padStart(3)}
                    </Text>
                    {s.total_tokens > 0 && (
                      <Text color={s.total_tokens > 150000 ? colors.tokenHigh : colors.textDim}>
                        {" "}{"\uEDE8"} {formatTokens(s.total_tokens)}
                      </Text>
                    )}
                    {s.cost_usd > 0 && (
                      <Text color={colors.tokenHigh}>
                        {" "}{formatCost(s.cost_usd)}
                      </Text>
                    )}
                    <Text dimColor>
                      {" "}{"\uF017"} {timeAgo(s.mod_time)}
                    </Text>
                  </Box>
                  {/* Thin separator — matches Go TUI's horizontal rule between cards */}
                  <Box paddingX={1}>
                    <Text color={colors.textMuted}>{"─".repeat(Math.max(10, cols - 4))}</Text>
                  </Box>
                </Box>
              );
            })}
          </Box>
        );
      })}

      {sessions.length === 0 && !loading && (
        <Box paddingX={1}>
          <Text dimColor>No sessions found</Text>
        </Box>
      )}
    </Box>
  );
}

