  colors.accent,
  colors.info,
  colors.textSecondary,
  colors.textDim,
  colors.textMuted,
];

export function BrailleSpinner() {
  return (
    <Box>
      {BEAD_COLORS.map((clr, i) => (
        <Text key={i} color={clr}>
          {BEAD}
        </Text>
      ))}
    </Box>
  );
}

