  1→import type { ReactNode } from "react";
  2→import { Box, Text } from "ink";
  3→import type { DisplayMessage, DisplayItem } from "../api.js";
  4→import {
  5→  formatDuration,
  6→  formatTokens,
  7→  truncate,
  8→  roleColor,
  9→  roleIcon,
 10→  formatJson,
 11→} from "../lib/format.js";
 12→import { colors, getItemColor, getTeamColor } from "../lib/theme.js";
 13→import { getItemIcon, getItemName, getItemSummary } from "../lib/items.js";
 14→import { StatsBar, statsFromMessage } from "./StatsBar.js";
 15→import { BrailleSpinner, OngoingDot } from "./OngoingDots.js";
 16→import { stableWindow } from "../lib/window.js";
 17→
 18→/** Max content width — matches Go TUI's maxContentWidth. */
 19→const MAX_CONTENT_WIDTH = 160;
 20→
 21→/** Limit text to maxLines while preserving newlines. Appends "…" if truncated. */
 22→function limitLines(text: string, maxLines: number): string {
 23→  const lines = text.split("\n");
 24→  if (lines.length <= maxLines) return text;
 25→  return lines.slice(0, maxLines).join("\n") + "\n…(" + (lines.length - maxLines) + " more lines)";
 26→}
 27→
 28→/** Clamp each line to maxWidth so bordered boxes don't overflow the terminal. */
 29→function clampLines(text: string, maxWidth: number): string {
 30→  return text
 31→    .split("\n")
 32→    .map((line) => (line.length > maxWidth ? line.slice(0, maxWidth - 1) + "…" : line))
 33→    .join("\n");
 34→}
 35→
 36→interface DetailViewProps {
 37→  message: DisplayMessage;
 38→  selectedItem: number;
 39→  expandedItems: Set<number>;
 40→  ongoing: boolean;
 41→  depth?: number;
 42→}
 43→
 44→function itemBorderColor(item: DisplayItem, isSelected: boolean): string {
 45→  if (isSelected) return colors.accent;
 46→  // Subagent items with messages get their team color
 47→  if (item.subagent_messages.length > 0 && item.team_color) {
 48→    return getTeamColor(item.team_color);
 49→  }
 50→  return getItemColor(item.item_type, !!item.tool_error);
 51→}
 52→
 53→export function DetailView({
 54→  message,
 55→  selectedItem,
 56→  expandedItems,
 57→  ongoing,
 58→  depth = 0,
 59→}: DetailViewProps) {
 60→  const cols = process.stdout.columns || 80;
 61→  const contentWidth = Math.min(cols, MAX_CONTENT_WIDTH);
 62→  const stats = statsFromMessage(message);
 63→  const items = message.items;
 64→
 65→  const windowSize = (process.stdout.rows || 24) - 8;
 66→  const { start, end } = stableWindow("detail", selectedItem, items.length, windowSize);
 67→  const visible = items.slice(start, end);
 68→
 69→  // Fixed-width name column — computed from ALL items so it doesn't shift (matches Go TUI's 12-char pad)
 70→  const maxNameLen = Math.max(12, ...items.map((it) => getItemName(it).length));
 71→
 72→  return (
 73→    <Box flexDirection="column">
 74→      {/* Message header — round border (matches Go TUI's RoundedBorder) */}
 75→      <Box
 76→        flexDirection="column"
 77→        borderStyle="round"
 78→        borderColor={colors.border}
 79→        paddingX={2}
 80→        width={contentWidth}
 81→      >
 82→        <Box gap={1}>
 83→          {depth > 0 ? <Text dimColor>{"\u25B8".repeat(depth)} </Text> : null}
 84→          <Text bold color={roleColor(message.role)}>
 85→            {roleIcon(message.role)}{" "}
 86→            {message.role === "claude" ? "Claude" : message.role === "user" ? "User" : "System"}
 87→          </Text>
 88→          {message.subagent_label ? (
 89→            <Text color={colors.itemAgent}>[{message.subagent_label}]</Text>
 90→          ) : null}
 91→          <StatsBar stats={stats} />
 92→          {ongoing ? <BrailleSpinner /> : null}
 93→        </Box>
 94→        {items.length > 0 ? (
 95→          <Text dimColor wrap="truncate">
 96→            {truncate(message.content, contentWidth - 8)}
 97→          </Text>
 98→        ) : null}
 99→      </Box>
100→
101→      {/* Full content when no items */}
102→      {items.length === 0 ? (
103→        <Box paddingX={2} flexDirection="column">
104→          <Text wrap="wrap">{message.content}</Text>
105→        </Box>
106→      ) : (
107→        <Box flexDirection="column" paddingTop={1}>
108→          {visible.map((item, i) => {
109→            const idx = start + i;
110→            const isSelected = idx === selectedItem;
111→            const isExpanded = expandedItems.has(idx);
112→            const clr = itemBorderColor(item, isSelected);
113→            const hasAgent = item.subagent_messages.length > 0;
114→            const teamClr = item.team_color ? getTeamColor(item.team_color) : undefined;
115→            const accentClr = hasAgent && teamClr ? teamClr : clr;
116→
117→            // Go TUI format: {cursor} {icon} {name:<maxNameLen} {summary}  {tokens:>9} {duration:<5}
118→            const summaryMaxLen = contentWidth - maxNameLen - 30; // leave room for tokens + duration
119→
120→            return (
121→              <Box
122→                key={`${item.item_type}-${idx}-${item.tool_name || item.agent_id || ""}`}
123→                flexDirection="row"
124→                marginBottom={0}
125→              >
126→                {/* Left accent — double bar for subagents with messages */}
127→                <Text color={accentClr}>{hasAgent ? "┃" : "│"}</Text>
128→                <Box flexDirection="column" flexGrow={1} paddingLeft={1}>
129→                  {/* Item header row — Go TUI aligned format */}
130→                  <Box>
131→                    {/* Cursor + icon + name (fixed width) */}
132→                    <Text bold={isSelected} inverse={isSelected} color={accentClr}>
133→                      {isExpanded ? "\u02C5" : "\u02C3"} {getItemIcon(item)}{" "}
134→                      {getItemName(item).padEnd(maxNameLen)}
135→                    </Text>
136→                    {/* Summary */}
137→                    {getItemSummary(item) ? (
138→                      <Text dimColor> {truncate(getItemSummary(item), summaryMaxLen)}</Text>
139→                    ) : null}
140→                    {/* Spacer */}
141→                    <Box flexGrow={1} />
142→                    {/* Right-aligned: tokens + duration */}
143→                    {item.token_count > 0 ? (
144→                      <Text dimColor>{formatTokens(item.token_count).padStart(9)}</Text>
145→                    ) : null}
146→                    {item.duration_ms > 0 ? (
147→                      <Text dimColor> {formatDuration(item.duration_ms).padEnd(5)}</Text>
148→                    ) : null}
149→                    {item.subagent_ongoing ? <OngoingDot /> : null}
150→                    {hasAgent ? (
151→                      <Text color={teamClr || colors.itemAgent} dimColor>
152→                        {" "}
153→                        [{item.subagent_messages.length} msg]
154→                      </Text>
155→                    ) : null}
156→                  </Box>
157→
158→                  {/* Expanded body */}
159→                  {isExpanded && <DetailItemBody item={item} cols={contentWidth} />}
160→                </Box>
161→              </Box>
162→            );
163→          })}
164→        </Box>
165→      )}
166→    </Box>
167→  );
168→}
169→
170→/** Bordered container with a label in the top-left corner. */
171→function Section({
172→  label,
173→  width,
174→  children,
175→}: {
176→  label: string;
177→  width: number;
178→  children: ReactNode;
179→}) {
180→  return (
181→    <Box flexDirection="column" borderStyle="round" borderColor={colors.border} width={width}>
182→      <Box paddingX={1} flexDirection="column">
183→        <Text bold color={colors.textMuted}>
184→          {label}
185→        </Text>
186→        <Box marginTop={1} flexDirection="column">
187→          {children}
188→        </Box>
189→      </Box>
190→    </Box>
191→  );
192→}
193→
194→/** Plain bordered container (no label). */
195→function Container({ width, children }: { width: number; children: ReactNode }) {
196→  return (
197→    <Box flexDirection="column" borderStyle="round" borderColor={colors.border} width={width}>
198→      <Box paddingX={1} flexDirection="column">
199→        {children}
200→      </Box>
201→    </Box>
202→  );
203→}
204→
205→const MAX_BODY_LINES = 40;
206→// border (2) + paddingX (2) + left-accent bar + padding (2) = ~6
207→const BOX_OVERHEAD = 6;
208→
209→function DetailItemBody({ item, cols }: { item: DisplayItem; cols: number }) {
210→  // Width available inside the box for text content
211→  const innerWidth = cols - BOX_OVERHEAD - 4; // 4 = border(2) + paddingX(2) inside the box
212→  const boxWidth = cols - BOX_OVERHEAD;
213→  const clamp = (text: string) => clampLines(limitLines(text, MAX_BODY_LINES), innerWidth);
214→
215→  switch (item.item_type) {
216→    case "Thinking":
217→      return (
218→        <Container width={boxWidth}>
219→          <Text color={colors.itemThinking} wrap="truncate">
220→            {clamp(item.text || "Thinking content is not recorded in session logs.")}
221→          </Text>
222→        </Container>
223→      );
224→    case "Output":
225→      return (
226→        <Container width={boxWidth}>
227→          <Text wrap="truncate">{clamp(item.text)}</Text>
228→        </Container>
229→      );
230→    case "ToolCall":
231→      return (
232→        <Box flexDirection="column">
233→          {item.tool_input && (
234→            <Section label="INPUT" width={boxWidth}>
235→              <Text dimColor wrap="truncate">
236→                {clamp(formatJson(item.tool_input))}
237→              </Text>
238→            </Section>
239→          )}
240→          {item.tool_result && (
241→            <Section label="RESULT" width={boxWidth}>
242→              <Text color={item.tool_error ? colors.error : undefined} wrap="truncate">
243→                {clamp(item.tool_result)}
244→              </Text>
245→            </Section>
246→          )}
247→        </Box>
248→      );
249→    case "Subagent":
