  1→import type { ReactNode } from "react";
  2→import { Box, Text } from "ink";
  3→import type { DisplayMessage } from "../api.js";
  4→import { formatTokens, formatDuration } from "../lib/format.js";
  5→import { colors } from "../lib/theme.js";
  6→
  7→export interface Stats {
  8→  tokens: number;
  9→  toolCount: number;
 10→  thinkingCount: number;
 11→  outputCount: number;
 12→  durationMs: number;
 13→  agentCount: number;
 14→  spawnCount: number;
 15→}
 16→
 17→export function statsFromMessage(msg: DisplayMessage): Stats {
 18→  const agentCount = msg.items.filter(
 19→    (it) => it.item_type === "Subagent" || it.subagent_messages.length > 0,
 20→  ).length;
 21→  return {
 22→    tokens: msg.tokens_raw,
 23→    toolCount: msg.tool_call_count,
 24→    thinkingCount: msg.thinking_count,
 25→    outputCount: msg.output_count,
 26→    durationMs: msg.duration_ms,
 27→    agentCount,
 28→    spawnCount: msg.teammate_spawns,
 29→  };
 30→}
 31→
 32→function hasAny(s: Stats): boolean {
 33→  return (
 34→    s.tokens > 0 ||
 35→    s.toolCount > 0 ||
 36→    s.thinkingCount > 0 ||
 37→    s.outputCount > 0 ||
 38→    s.durationMs > 0 ||
 39→    s.agentCount > 0 ||
 40→    s.spawnCount > 0
 41→  );
 42→}
 43→
 44→/** Middle dot separator for stats. */
 45→function Dot() {
 46→  return <Text color={colors.textMuted}> · </Text>;
 47→}
 48→
 49→export function StatsBar({ stats }: { stats: Stats }) {
 50→  if (!hasAny(stats)) return null;
 51→
 52→  // Build parts array, then join with dots (matches Go TUI stat row)
 53→  const parts: { id: string; node: ReactNode }[] = [];
 54→
 55→  if (stats.thinkingCount > 0) {
 56→    parts.push({
 57→      id: "think",
 58→      node: (
 59→        <Text dimColor color={colors.itemThinking}>
 60→          {"\uF0EB"} {stats.thinkingCount}
 61→        </Text>
 62→      ),
 63→    });
 64→  }
 65→  if (stats.toolCount > 0) {
 66→    parts.push({
