    s.toolCount > 0 ||
    s.thinkingCount > 0 ||
    s.outputCount > 0 ||
    s.durationMs > 0 ||
    s.agentCount > 0 ||
    s.spawnCount > 0
  );
}

/** Middle dot separator for stats. */
function Dot() {
  return <Text color={colors.textMuted}> · </Text>;
}

