398→// -- Detail rendering ---------------------------------------------------------
399→
400→// renderDetailContent renders the full detail content for the current message.
401→// Used by both computeDetailMaxScroll and viewDetail to avoid duplication.
402→func (m model) renderDetailContent(msg message, width int) rendered {
403→	// AI messages with items get the structured items view.
404→	if msg.role == RoleClaude && len(msg.items) > 0 {
405→		return newRendered(m.renderDetailItemsContent(msg, width))
406→	}
407→
408→	var header, body string
409→	switch msg.role {
410→	case RoleClaude:
411→		header = m.renderDetailHeader(msg, width).content
412→		body = m.md.renderMarkdown(msg.content, width-4)
413→	case RoleUser:
414→		header = userHeaderLine(msg)
415→		body = m.md.renderMarkdown(msg.content, width-4)
416→	case RoleSystem:
417→		header = Icon.System.Render() +
418→			" " + StyleSecondary.Render("System") +
419→			"  " + StyleDim.Render(msg.timestamp)
420→		body = StyleDim.Render(msg.content)
421→	case RoleCompact:
422→		return newRendered(renderCompactMessage(msg, width))
423→	}
424→
425→	return newRendered(header + "\n\n" + body)
426→}
427→
428→// renderDetailItemsContent renders the full content for an AI message with
429→// structured items (header + items list + expanded content). Returns the
430→// complete string before scrolling is applied.
431→//
432→// Uses the flat visible-row list so that expanded subagent children are
433→// interleaved with parent items and can receive cursor highlights.
434→func (m model) renderDetailItemsContent(msg message, width int) string {
435→	header := m.renderDetailHeader(msg, width).content
436→	rows := buildVisibleRows(msg.items, m.detailExpanded)
437→
438→	childIndent := "    " // 4 spaces for child rows
439→	childWidth := max(width-4, 20)
440→
441→	var itemLines []string
442→	for ri, row := range rows {
443→		if row.childIndex == -1 {
444→			// Parent row.
445→			isExp := m.detailExpanded[row.parentIndex]
446→			rowStr := m.renderDetailItemRow(row.item, ri, m.detailCursor, isExp, width)
447→
448→			if isExp {
449→				if row.item.itemType == parser.ItemSubagent && row.item.subagentProcess != nil {
450→					// Trace header separates parent from its children.
451→					hdr := renderTraceHeader(row.item)
452→					rowStr += "\n" + childIndent + hdr
453→				} else {
454→					// Non-subagent or subagent without process: inline content.
455→					expanded := m.renderDetailItemExpanded(row.item, width)
456→					if expanded.content != "" {
457→						rowStr += "\n" + expanded.content
458→					}
459→				}
460→			}
461→			itemLines = append(itemLines, rowStr)
462→		} else {
463→			// Child row (indented, belongs to an expanded subagent).
464→			key := visibleRowKey{row.parentIndex, row.childIndex}
465→			isExp := m.detailChildExpanded[key]
466→			childRow := m.renderDetailItemRow(row.item, ri, m.detailCursor, isExp, childWidth)
467→
468→			rowStr := childIndent + childRow
469→			if isExp {
470→				expanded := m.renderDetailItemExpanded(row.item, childWidth)
471→				if expanded.content != "" {
472→					rowStr += "\n" + indentBlock(expanded.content, childIndent)
473→				}
474→			}
475→			itemLines = append(itemLines, rowStr)
476→		}
477→	}
478→
479→	return header + "\n\n" + strings.Join(itemLines, "\n")
480→}
481→
482→// renderTraceHeader renders the "Execution Trace" separator between a parent
483→// subagent row and its child trace items. Not a navigable row.
484→func renderTraceHeader(parent displayItem) string {
485→	items := buildTraceItems(parent)
486→	toolCount, msgCount := traceItemStats(items)
487→
488→	dimStyle := StyleDim
489→	traceIcon := Icon.System.WithColor(ColorTextDim)
490→	traceLabel := StylePrimaryBold.Render("Execution Trace")
491→	dot := dimStyle.Render(" " + Icon.Dot.Glyph + " ")
492→	countStr := dimStyle.Render(fmt.Sprintf("%d tool calls, %d messages", toolCount, msgCount))
493→
494→	return traceIcon + "  " + traceLabel + dot + countStr
495→}
496→
497→// renderDetailItemRow renders a single item row in the detail view.
498→// Format: {cursor} {indicator} {name:<12} {summary}  {tokens} {duration}
499→// isExpanded controls the cursor chevron direction (down vs right).
500→func (m model) renderDetailItemRow(item displayItem, index, cursorIndex int, isExpanded bool, width int) string {
501→	// Cursor indicator: drillable items get a distinct arrow, expanded items
502→	// get chevron-down, collapsed items get chevron-right.
503→	cursor := "  "
504→	if index == cursorIndex {
505→		if item.subagentProcess != nil {
506→			cursor = Icon.DrillDown.RenderBold() + " "
507→		} else if isExpanded {
508→			cursor = Icon.Expanded.RenderBold() + " "
509→		} else {
510→			cursor = Icon.Collapsed.Render() + " "
511→		}
512→	}
513→
514→	// Type indicator and name
515→	var indicator, name string
516→
517→	switch item.itemType {
518→	case parser.ItemThinking:
519→		indicator = Icon.Thinking.Render()
520→		name = "Thinking"
521→	case parser.ItemOutput:
522→		indicator = Icon.Output.Render()
523→		name = "Output"
524→		if item.toolName != "" {
525→			name = item.toolName
526→		}
527→	case parser.ItemToolCall:
528→		indicator = toolCategoryIcon(item.toolCategory, item.toolError)
529→		name = item.toolName
530→	case parser.ItemSubagent:
531→		if item.teamColor != "" {
532→			indicator = Icon.Subagent.WithColor(teamColor(item.teamColor))
533→		} else {
534→			indicator = toolCategoryIcon(item.toolCategory, item.toolError)
535→		}
536→		// Team agents show member name ("file-counter"), others show type ("Explore").
537→		if item.teamMemberName != "" {
538→			name = item.teamMemberName
539→		} else {
540→			name = item.subagentType
541→		}
542→		if name == "" {
543→			name = "Subagent"
544→		}
545→	case parser.ItemTeammateMessage:
546→		if item.teamColor != "" {
547→			indicator = Icon.Teammate.WithColor(teamColor(item.teamColor))
548→		} else {
549→			indicator = Icon.Teammate.Render()
550→		}
551→		name = item.teammateID
552→		if name == "" {
553→			name = "Teammate"
554→		}
555→	}
556→
557→	// Pad name to 12 chars
558→	nameStr := fmt.Sprintf("%-12s", name)
559→	var nameRendered string
560→	if item.teamColor != "" {
561→		nameRendered = lipgloss.NewStyle().Bold(true).Foreground(teamColor(item.teamColor)).Render(nameStr)
562→	} else {
563→		nameRendered = StylePrimaryBold.Render(nameStr)
564→	}
565→
566→	// Ongoing spinner for subagent items: 1 glyph + 1 space, or 2 spaces for alignment.
567→	spinnerSlot := "  "
568→	if item.itemType == parser.ItemSubagent && item.subagentOngoing {
569→		frame := SpinnerFrames[m.animFrame%len(SpinnerFrames)]
570→		spinnerSlot = lipgloss.NewStyle().Foreground(ColorOngoing).Render(frame) + " "
571→	}
572→
573→	// Summary
574→	var summary string
575→	switch item.itemType {
576→	case parser.ItemThinking, parser.ItemOutput:
577→		summary = parser.Truncate(item.text, 40)
578→	case parser.ItemToolCall:
579→		summary = item.toolSummary
580→	case parser.ItemSubagent:
581→		summary = item.subagentDesc
582→		if summary == "" {
583→			summary = item.toolSummary
584→		}
585→	case parser.ItemTeammateMessage:
586→		summary = parser.Truncate(item.text, 60)
587→	}
588→	// Suppress summary when it just repeats the tool name (common for MCP
589→	// tools with empty input, where summaryDefault returns the name).
590→	if summary == item.toolName {
591→		summary = ""
592→	}
593→	summaryRendered := StyleSecondary.Render(summary)
594→
595→	// Right-side: tokens + duration.
596→	// Prefer subagent process stats when linked (actual internal consumption).
597→	tokCount := item.tokenCount
598→	durMs := item.durationMs
599→	if item.subagentProcess != nil {
600→		if t := item.subagentProcess.Usage.TotalTokens(); t > 0 {
601→			tokCount = t
602→		}
603→		if d := item.subagentProcess.DurationMs; d > 0 {
604→			durMs = d
605→		}
606→	}
607→	// Build fixed-width right side so tok and dur columns align across all rows.
608→	// "%*s  %-*s": tok right-aligned in detailItemTokWidth, dur left-aligned in detailItemDurWidth.
609→	// Empty strings produce spaces, keeping the total width constant.
610→	tokStr := ""
611→	if tokCount > 0 {
612→		tokStr = fmt.Sprintf("~%s tok", formatTokens(tokCount))
613→	}
614→	durStr := ""
615→	if durMs >= 1000 {
616→		durStr = formatDuration(durMs)
617→	} else if durMs > 0 {
618→		durStr = "<1s"
619→	}
620→	var rightSide string
621→	if tokStr != "" || durStr != "" {
622→		tokPart := StyleDim.Render(fmt.Sprintf("%*s", detailItemTokWidth, tokStr))
623→		durPart := StyleDim.Render(fmt.Sprintf("%-*s", detailItemDurWidth, durStr))
624→		// When both present, prefix duration with a green dot separator.
625→		// The dot + space adds 2 visible chars; pad the else branch to match.
626→		if tokStr != "" && durStr != "" {
627→			dot := lipgloss.NewStyle().Foreground(ColorOngoing).Render(Icon.Dot.Glyph)
628→			rightSide = tokPart + "  " + dot + " " + durPart
629→		} else {
630→			rightSide = tokPart + "    " + durPart
631→		}
632→	}
633→
634→	var left string
635→	if summary != "" {
636→		left = cursor + indicator + " " + nameRendered + spinnerSlot + StyleDim.Render("- ") + summaryRendered
637→	} else {
638→		left = cursor + indicator + " " + nameRendered + spinnerSlot
639→	}
640→	return spaceBetween(left, rightSide, width)
641→}
