722→// renderTaskInput renders structured metadata for a Task item without a linked
723→// subagent process. Extracts key fields from the JSON input and truncates the
724→// prompt field (which can be thousands of characters) instead of dumping raw JSON.
725→// Falls back to renderToolExpanded if JSON parsing fails.
726→func (m model) renderTaskInput(item displayItem, wrapWidth int, indent string) string {
727→	var fields map[string]json.RawMessage
728→	if err := json.Unmarshal([]byte(item.toolInput), &fields); err != nil {
729→		return m.renderToolExpanded(item, wrapWidth, indent)
730→	}
731→
732→	labelStyle := StyleSecondaryBold
733→	valueStyle := StyleDim
734→
735→	var lines []string
736→
737→	// Extract and render key metadata fields.
738→	for _, key := range []string{"description", "subagent_type", "team_name", "name", "model"} {
739→		raw, ok := fields[key]
740→		if !ok {
741→			continue
742→		}
743→		var val string
744→		if json.Unmarshal(raw, &val) != nil || val == "" {
745→			continue
746→		}
747→		lines = append(lines, indent+labelStyle.Render(key+":")+
748→			" "+valueStyle.Render(val))
749→	}
750→
751→	// Prompt: truncate to avoid wall-of-text.
752→	if raw, ok := fields["prompt"]; ok {
753→		var prompt string
754→		if json.Unmarshal(raw, &prompt) == nil && prompt != "" {
755→			const maxPrompt = 500
756→			if len(prompt) > maxPrompt {
757→				prompt = prompt[:maxPrompt] + Icon.Ellipsis.Glyph
758→			}
759→			// Collapse newlines for a compact preview.
760→			prompt = strings.ReplaceAll(prompt, "\n", " ")
761→			promptRendered := valueStyle.Width(wrapWidth).Render(prompt)
762→			lines = append(lines, indent+labelStyle.Render("prompt:")+
763→				" "+promptRendered)
764→		}
765→	}
766→
767→	// Show the result if present (tool completed).
768→	if item.toolResult != "" || item.toolError {
769→		if len(lines) > 0 {
770→			sepStyle := StyleMuted
771→			lines = append(lines, indent+sepStyle.Render(strings.Repeat("-", wrapWidth)))
772→		}
773→		if item.toolError {
774→			lines = append(lines, indent+StyleErrorBold.Render("Error:"))
775→		} else {
776→			lines = append(lines, indent+labelStyle.Render("Result:"))
777→		}
778→		lines = append(lines, indentBlock(
779→			m.highlightOrDim(item.toolResult, wrapWidth), indent))
780→	}
781→
782→	if len(lines) == 0 {
783→		return m.renderToolExpanded(item, wrapWidth, indent)
784→	}
785→	return strings.Join(lines, "\n")
786→}
