15→  { key: "/", label: "search" },
16→  { key: "q", label: "quit" },
17→];
18→
19→const listKeys: KeyHint[] = [
20→  { key: "h", label: "sidebar" },
21→  { key: "j/k", label: "nav" },
22→  { key: "G/g", label: "jump" },
23→  { key: "Tab", label: "toggle" },
24→  { key: "Enter", label: "detail" },
