29→
30→const listKeysWithTeams: KeyHint[] = [
31→  ...listKeys.slice(0, 5),
32→  { key: "t", label: "tasks" },
33→  ...listKeys.slice(5),
34→];
35→
36→const detailKeys: KeyHint[] = [
37→  { key: "j/k", label: "items" },
38→  { key: "Enter/Tab", label: "toggle" },
39→  { key: "e/c", label: "expand" },
40→  { key: "q/Esc", label: "back" },
41→];
42→
43→const debugKeys: KeyHint[] = [{ key: "q/Esc", label: "back" }];
44→
45→const teamKeys: KeyHint[] = [{ key: "q/Esc", label: "back" }];
46→
47→function getKeys(view: ViewState, hasTeams: boolean): KeyHint[] {
48→  switch (view) {
49→    case "picker":
50→      return pickerKeys;
51→    case "list":
52→      return hasTeams ? listKeysWithTeams : listKeys;
53→    case "detail":
54→      return detailKeys;
55→    case "debug":
56→      return debugKeys;
57→    case "team":
58→      return teamKeys;
59→  }
60→}
61→
62→interface KeybindBarProps {
63→  view: ViewState;
64→  hasTeams: boolean;
65→  position?: string;
66→}
67→
68→export function KeybindBar({ view, hasTeams, position }: KeybindBarProps) {
69→  const keys = getKeys(view, hasTeams);
70→
71→  return (
