  1→import { Box, Text } from "ink";
  2→import type { DisplayMessage } from "../api.js";
  3→import { truncate, roleColor, roleIcon, shortModel, modelColor, firstLine } from "../lib/format.js";
  4→import { colors, getRoleBorderColor, getItemColor, getTeamColor } from "../lib/theme.js";
  5→import { getItemIcon, getItemName } from "../lib/items.js";
  6→import { StatsBar, statsFromMessage } from "./StatsBar.js";
  7→import { BrailleSpinner } from "./OngoingDots.js";
  8→import { stableWindow } from "../lib/window.js";
  9→import {
 10→  IconSelected2,
 11→  IconBarSingle,
 12→  IconBarDouble,
 13→  IconOngoingDot,
 14→  IconHRule,
 15→  IconDot,
 16→} from "../lib/icons.js";
 17→
 18→/** Max content width — matches Go TUI's maxContentWidth. */
 19→const MAX_CONTENT_WIDTH = 160;
 20→
 21→interface MessageListProps {
 22→  messages: DisplayMessage[];
 23→  selectedIndex: number;
 24→  expandedSet: Set<number>;
 25→  ongoing: boolean;
 26→}
 27→
 28→export function MessageList({ messages, selectedIndex, expandedSet, ongoing }: MessageListProps) {
 29→  const cols = process.stdout.columns || 80;
 30→  const contentWidth = Math.min(cols, MAX_CONTENT_WIDTH);
 31→  // Each message card: border top(1) + header(1) + body(1) + stats(1) + border bottom(1) = 5 lines
 32→  // Account for InfoBar(3) + KeybindBar(3) = 6 lines of chrome
 33→  const rows = process.stdout.rows || 24;
 34→  const windowSize = Math.max(3, Math.floor((rows - 6) / 5));
 35→  const { start, end } = stableWindow("messages", selectedIndex, messages.length, windowSize);
 36→  const visible = messages.slice(start, end);
 37→
 38→  if (messages.length === 0) {
 39→    return (
 40→      <Box paddingX={1}>
 41→        <Text dimColor>No messages loaded</Text>
 42→      </Box>
 43→    );
 44→  }
 45→
 46→  return (
 47→    <Box flexDirection="column">
 48→      {visible.map((msg, i) => {
 49→        const idx = start + i;
 50→        const isSelected = idx === selectedIndex;
 51→        const isExpanded = expandedSet.has(idx);
 52→        const isLast = idx === messages.length - 1;
 53→        const stats = statsFromMessage(msg);
 54→        const model = msg.model ? shortModel(msg.model) : "";
 55→
 56→        // System messages — centered dashed separator (matches Go TUI)
 57→        if (msg.role === "compact") {
 58→          return (
 59→            <Box key={`compact-${idx}`} paddingX={1} justifyContent="center">
 60→              <Text dimColor>
 61→                {IconHRule.repeat(6)} {msg.content} {IconHRule.repeat(6)}
 62→              </Text>
 63→            </Box>
 64→          );
 65→        }
 66→
 67→        if (msg.role === "system") {
 68→          return (
 69→            <Box key={`sys-${idx}`} justifyContent="center" paddingX={2}>
 70→              <Text color={colors.textMuted}>
 71→                {IconHRule}
 72→                {IconHRule} {roleIcon("system")} System {IconDot}{" "}
 73→                {truncate(msg.content, contentWidth - 20)} {IconHRule}
 74→                {IconHRule}
 75→              </Text>
 76→            </Box>
 77→          );
 78→        }
 79→
 80→        const bodyWidth = contentWidth - 8; // border(2) + paddingX(4) + accent bar(2)
 81→        const contentPreview = isExpanded
 82→          ? msg.content
 83→          : truncate(firstLine(msg.content), bodyWidth);
 84→        const borderClr = isSelected ? colors.accent : getRoleBorderColor(msg.role, msg.is_error);
 85→
 86→        return (
 87→          <Box
 88→            key={`msg-${idx}-${msg.role}`}
 89→            flexDirection="column"
 90→            borderStyle="round"
 91→            borderColor={borderClr}
 92→            paddingX={2}
 93→          >
 94→            {/* Header: role icon + name + model + stats */}
 95→            <Box gap={1}>
 96→              <Text
 97→                bold
 98→                inverse={isSelected}
 99→                color={isSelected ? colors.accent : roleColor(msg.role)}
100→              >
101→                {isSelected ? `${IconSelected2} ` : "  "}
102→                {roleIcon(msg.role)} {msg.role === "claude" ? "Claude" : "User"}
103→              </Text>
104→              {model ? (
105→                <Text color={modelColor(msg.model)} dimColor={!isSelected}>
106→                  {model}
107→                </Text>
108→              ) : null}
109→              {msg.subagent_label ? (
110→                <Text color={colors.itemAgent} dimColor>
111→                  [{msg.subagent_label}]
112→                </Text>
113→              ) : null}
114→              {isLast && ongoing ? <BrailleSpinner /> : null}
115→              {isSelected ? (
116→                <Text dimColor>
117→                  [{idx + 1}/{messages.length}]
118→                </Text>
119→              ) : null}
120→            </Box>
121→
122→            {/* Body content — indented 2 spaces under header (matches Go TUI) */}
123→            <Box paddingLeft={2}>
124→              <Text dimColor={!isSelected} wrap={isExpanded ? "wrap" : "truncate"}>
125→                {contentPreview}
126→              </Text>
127→            </Box>
128→
129→            {/* Stats row */}
130→            <StatsBar stats={stats} />
131→
132→            {/* Expanded items tree */}
133→            {isExpanded && msg.items.length > 0 && (
134→              <Box flexDirection="column" paddingLeft={2} marginTop={0}>
135→                {msg.items.map((item) => (
136→                  <Box
137→                    key={`${idx}-${item.item_type}-${item.tool_name || item.agent_id || ""}-${item.duration_ms}`}
138→                    flexDirection="row"
139→                  >
140→                    <Text color={item.team_color ? getTeamColor(item.team_color) : colors.border}>
141→                      {item.subagent_messages.length > 0 ? IconBarDouble : IconBarSingle}
142→                    </Text>
143→                    <Box paddingLeft={1}>
144→                      <Text
145→                        color={
146→                          item.team_color
