                      </Text>
                    </Box>
                  </Box>
                ))}
              </Box>
            )}
          </Box>
        );
      })}
    </Box>
  );
}

import { useMemo } from "react";
import { Box, Text } from "ink";
import type { DisplayMessage, SessionMeta, SessionTotals } from "../api.js";
import { formatTokens, formatCost } from "../lib/format.js";
import { colors, getContextColor } from "../lib/theme.js";
import { BrailleSpinner } from "./OngoingDots.js";
import { IconBranch } from "../lib/icons.js";

interface InfoBarProps {
  meta: SessionMeta;
  messages: DisplayMessage[];
  sessionTotals: SessionTotals;
  sessionPath: string;
  ongoing: boolean;
}

function shortPath(cwd: string): string {
  if (!cwd) return "";
  const parts = cwd.split("/").filter(Boolean);
  return parts[parts.length - 1] ?? cwd;
}

function shortMode(mode: string): string {
  switch (mode) {
    case "acceptEdits":
      return "auto-edit";
    case "bypassPermissions":
      return "yolo";
    case "plan":
      return "plan";
    default:
      return mode;
  }
}

function contextPercent(msgs: DisplayMessage[]): number {
  const contextWindowSize = 1_000_000;
  for (let i = msgs.length - 1; i >= 0; i--) {
    if (msgs[i].role === "claude" && msgs[i].context_tokens > 0) {
      return Math.min(Math.floor((msgs[i].context_tokens * 100) / contextWindowSize), 100);
    }
  }
  return -1;
}

function modeColor(mode: string): string {
  switch (mode) {
    case "bypassPermissions":
      return colors.pillBypass;
    case "acceptEdits":
      return colors.pillAcceptEdits;
    case "plan":
      return colors.pillPlan;
    default:
      return colors.textPrimary;
  }
}

/** Middle dot separator — matches Go TUI's spaceBetween pattern. */
function Dot() {
  return <Text color={colors.textMuted}> · </Text>;
}

export function InfoBar({ meta, messages, sessionTotals, sessionPath, ongoing }: InfoBarProps) {
  const projectName = shortPath(meta.cwd);
  const sessionId = sessionPath.split("/").pop()?.replace(".jsonl", "") || "";
  const branch = meta.git_branch;
  const mode = meta.permission_mode;
  const ctxPct = useMemo(() => contextPercent(messages), [messages]);

  return (
    <Box paddingX={1} borderStyle="round" borderColor={colors.border}>
      {/* Left: path · branch · mode — Go TUI layout */}
      <Box>
        {projectName ? (
          <Text bold color={colors.accent}>
            {projectName}
          </Text>
        ) : null}
        {sessionId ? (
          <>
            <Dot />
            <Text color={colors.textDim}>{sessionId.slice(0, 8)}</Text>
          </>
        ) : null}
        {branch ? (
          <>
            <Dot />
            <Text color={colors.gitBranch}>
              {IconBranch} {branch}
            </Text>
          </>
        ) : null}
        {mode && mode !== "default" ? (
          <>
            <Dot />
            <Text color={modeColor(mode)} bold>
              {shortMode(mode)}
            </Text>
          </>
        ) : null}
      </Box>

      {/* Spacer */}
      <Box flexGrow={1} />

      {/* Right: ctx% · tokens · cost · ongoing */}
      <Box>
        {ctxPct >= 0 ? <Text color={getContextColor(ctxPct)}>ctx {ctxPct}%</Text> : null}
        {sessionTotals.total_tokens > 0 ? (
          <>
            <Dot />
            <Text color={colors.textDim}>{formatTokens(sessionTotals.total_tokens)} tok</Text>
          </>
        ) : null}
        {sessionTotals.cost_usd > 0 ? (
          <>
            <Dot />
            <Text color={colors.tokenHigh}>{formatCost(sessionTotals.cost_usd)}</Text>
          </>
        ) : null}
        {ongoing ? (
          <>
            {" "}
            <BrailleSpinner />
          </>
        ) : null}
      </Box>
    </Box>
  );
}

import { useMemo } from "react";
import { Box, Text } from "ink";
import { Spinner } from "@inkjs/ui";
import type { SessionInfo } from "../api.js";
import {
  formatTokens,
  formatCost,
  timeAgo,
  truncate,
  shortModel,
  modelColor,
} from "../lib/format.js";
import { OngoingDot } from "./OngoingDots.js";
import { colors } from "../lib/theme.js";
import { stableWindow } from "../lib/window.js";
import {
  IconSelected2,
  IconBarSingle,
  IconBranch,
  IconChat,
  IconClock,
  IconToken,
  IconSession,
  IconHRule,
} from "../lib/icons.js";

interface SessionPickerProps {
  sessions: SessionInfo[];
  loading: boolean;
  error: string;
  selectedIndex: number;
}

interface DateGroup {
  category: string;
  items: SessionInfo[];
}

function groupByDate(items: SessionInfo[]): DateGroup[] {
  const now = new Date();
  const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate());
  const yesterdayStart = new Date(todayStart.getTime() - 86400000);
  const weekStart = new Date(todayStart.getTime() - 7 * 86400000);
  const monthStart = new Date(todayStart.getTime() - 30 * 86400000);

  const groups: Record<string, SessionInfo[]> = {};
  const order = ["Today", "Yesterday", "This Week", "This Month", "Older"];

  for (const item of items) {
    const d = new Date(item.mod_time);
    let cat: string;
    if (d >= todayStart) cat = "Today";
    else if (d >= yesterdayStart) cat = "Yesterday";
    else if (d >= weekStart) cat = "This Week";
    else if (d >= monthStart) cat = "This Month";
    else cat = "Older";
    (groups[cat] ??= []).push(item);
  }

  for (const cat of order) {
    if (groups[cat]) {
      groups[cat].sort((a, b) => new Date(b.mod_time).getTime() - new Date(a.mod_time).getTime());
    }
  }

  return order
    .filter((cat) => groups[cat]?.length)
    .map((category) => ({ category, items: groups[category] }));
}

export function SessionPicker({ sessions, loading, error, selectedIndex }: SessionPickerProps) {
  const dateGroups = useMemo(() => groupByDate(sessions), [sessions]);

  const totalTokens = useMemo(
    () => sessions.reduce((sum, s) => sum + s.total_tokens, 0),
    [sessions],
  );
  const totalCost = useMemo(() => sessions.reduce((sum, s) => sum + s.cost_usd, 0), [sessions]);

  if (loading) {
    return (
      <Box padding={1}>
        <Spinner label="Discovering sessions..." />
      </Box>
    );
  }

  if (error) {
    return (
      <Box padding={1}>
        <Text color={colors.error}>{error}</Text>
      </Box>
    );
  }

  // 3 lines per session card (message + metadata + separator) + date headers
  const rows = process.stdout.rows || 24;
  const windowSize = Math.max(3, Math.floor((rows - 6) / 3));
  const { start, end } = stableWindow("picker", selectedIndex, sessions.length, windowSize);

  let flatIdx = 0;
  const cols = process.stdout.columns || 80;

  return (
    <Box flexDirection="column">
      {/* Header bar */}
      <Box paddingX={1} gap={2} borderStyle="round" borderColor={colors.border}>
        <Text bold>Sessions ({sessions.length})</Text>
        {totalTokens > 0 && <Text dimColor>{formatTokens(totalTokens)} tok</Text>}
        {totalCost > 0 && <Text color={colors.tokenHigh}>{formatCost(totalCost)}</Text>}
      </Box>

      {/* Session cards grouped by date */}
      {dateGroups.map((group) => {
        const groupItems = group.items.map((s) => {
          const idx = flatIdx++;
          return { session: s, idx };
        });

        const firstInGroup = groupItems[0]?.idx ?? 0;
        const lastInGroup = groupItems[groupItems.length - 1]?.idx ?? 0;
        if (lastInGroup < start || firstInGroup >= end) return null;

        return (
          <Box key={group.category} flexDirection="column">
            {firstInGroup >= start && firstInGroup < end && (
              <Box paddingX={1} marginTop={1}>
                <Text dimColor bold>
                  {group.category}
                </Text>
              </Box>
            )}
            {groupItems.map(({ session: s, idx }) => {
              if (idx < start || idx >= end) return null;
              const isSelected = idx === selectedIndex;
              const model = s.model ? shortModel(s.model) : "";
              const msgMaxLen = cols - 6;

              return (
                <Box key={s.path} flexDirection="column">
                  {/* Line 1: message preview */}
                  <Box>
                    <Text color={isSelected ? colors.accent : colors.border}>
                      {isSelected ? ` ${IconSelected2} ` : ` ${IconBarSingle} `}
                    </Text>
                    {s.is_ongoing && (
                      <>
                        <OngoingDot />
                        <Text> </Text>
                      </>
                    )}
                    <Text
                      bold={isSelected}
                      color={isSelected ? colors.accent : colors.textPrimary}
                      backgroundColor={isSelected ? colors.pickerSelectedBg : undefined}
                    >
                      {truncate(s.first_message || s.session_id, msgMaxLen)}
                    </Text>
                  </Box>
                  {/* Line 2: metadata with Nerd Font icons — matches Go TUI */}
                  <Box>
                    <Text color={isSelected ? colors.accent : colors.border}>
                      {isSelected ? ` ${IconSelected2} ` : ` ${IconBarSingle} `}
                    </Text>
                    {model && <Text color={modelColor(s.model)}>{model.padEnd(10)}</Text>}
                    {s.git_branch ? (
                      <Text color={colors.gitBranch}>
                        {" "}
                        {IconBranch} {truncate(s.git_branch, 20)}
                      </Text>
                    ) : null}
                    <Text dimColor>
                      {" "}
                      {IconChat} {String(s.turn_count).padStart(3)}
                    </Text>
                    {s.total_tokens > 0 && (
                      <Text color={s.total_tokens > 150000 ? colors.tokenHigh : colors.textDim}>
                        {" "}
                        {IconToken} {formatTokens(s.total_tokens)}
                      </Text>
                    )}
                    {s.cost_usd > 0 && (
                      <Text color={colors.tokenHigh}> {formatCost(s.cost_usd)}</Text>
                    )}
                    <Text dimColor>
                      {" "}
                      {IconSession} {s.session_id.slice(0, 8)}
                    </Text>
                    <Text dimColor>
                      {" "}
                      {IconClock} {timeAgo(s.mod_time)}
                    </Text>
                  </Box>
                  {/* Thin separator — matches Go TUI's horizontal rule between cards.
                      Use truncate so it doesn't wrap if flex container is narrower than cols. */}
                  <Box paddingX={1}>
                    <Text color={colors.textMuted} wrap="truncate">
                      {IconHRule.repeat(200)}
                    </Text>
                  </Box>
                </Box>
              );
            })}
          </Box>
        );
      })}

      {sessions.length === 0 && !loading && (
        <Box paddingX={1}>
          <Text dimColor>No sessions found</Text>
        </Box>
      )}
    </Box>
  );
}

